mapper.select:
select count(*)
from ODS_DWEQ_DM_DEVICE_D d
left join ODS_DWEQ_DM_ORG_D o on o.id = d.org_id
where (d.deleted is null or d.deleted = 0)
  and (o.deleted is null or o.deleted = 0)

  and d.device_type = #{deviceType}


  and d.asset_status = #{status}


  and (d.org_id = #{orgId} or instr('/' || nvl(o.path_ids, '') || '/', '/' || #{orgId} || '/') > 0)


  and d.manufacturer = #{manufacturer}


  and d.model = #{model}

select * from ( select d.id, d.iot_code, d.name, d.device_type, d.model, d.manufacturer, d.factory_date, d.run_date, d.asset_status, d.area_id, d.org_id, d.online_status, d.last_report_time, d.last_offline_time, d.remark, d.created_on, d.updated_on, b.monitor_id as monitor_id, m.name as monitor_name, row_number() over(order by d.updated_on desc nulls last, d.id desc) rn from ODS_DWEQ_DM_DEVICE_D d left join ODS_DWEQ_DM_ORG_D o on o.id = d.org_id left join ODS_DWEQ_DM_MONITOR_DEVICE_BIND_D b on b.id = ( select max(b1.id) from ODS_DWEQ_DM_MONITOR_DEVICE_BIND_D b1 where b1.device_id = d.id and (b1.deleted is null or b1.deleted = 0) ) left join ODS_DWEQ_DM_MONITOR_D m on m.id = b.monitor_id and (m.deleted is null or m.deleted = 0) where (d.deleted is null or d.deleted = 0) and (o.deleted is null or o.deleted = 0)
and d.device_type = #{deviceType}
and d.asset_status = #{status}
and (d.org_id = #{orgId} or instr('/' || nvl(o.path_ids, '') || '/', '/' || #{orgId} || '/') > 0)
and d.manufacturer = #{manufacturer}
and d.model = #{model}
) x where x.rn >= #{startRow} and x.rn <= #{endRow} order by x.rn
